func TestMessagesListQuery(t *testing.T) {
	var observedQuery string
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		observedQuery = r.URL.RawQuery
		_, _ = w.Write([]byte(`{
			"messages": [{"id":"m1","threadId":"t1"}],
			"nextPageToken": "next-1",
			"resultSizeEstimate": 12
		}`))
	}))
	defer srv.Close()
	withGmailBaseURL(t, srv.URL)

	configPath, tokenStorePath := withConfigPath(t)
	seedSendStore(t, tokenStorePath, "user@example.com", "gid-001")
	writeConfigPointingAt(t, configPath, "http://unused", "user@example.com")

	stdout, _, err := executeCmd(t, "--config", configPath, "--json", "messages", "list", "--query", "from:alice@example.com after:2026-05-01", "--limit", "5", "--page-token", "tok")
	if err != nil {
		t.Fatalf("messages list: %v", err)
	}
	for _, want := range []string{"q=from%3Aalice%40example.com+after%3A2026-05-01", "maxResults=5", "pageToken=tok"} {
		if !strings.Contains(observedQuery, want) {
			t.Fatalf("query %q missing %q", observedQuery, want)
		}
	}
	var env map[string]any
	if err := json.Unmarshal([]byte(stdout), &env); err != nil {
		t.Fatalf("parse output: %v\n%s", err, stdout)
	}
	if env["action"] != "messages.list" || env["next_page_token"] != "next-1" {
		t.Fatalf("envelope wrong: %v", env)
	}
}

func TestMessagesListFullFetchesBodies(t *testing.T) {
	plain := strings.TrimRight(base64.URLEncoding.EncodeToString([]byte("hello body")), "=")
	requests := map[string]int{}
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		requests[r.URL.Path]++
		switch {
		case strings.HasSuffix(r.URL.Path, "/users/me/messages") && r.URL.Query().Get("format") == "":
			_, _ = w.Write([]byte(`{"messages":[{"id":"m1","threadId":"t1"}]}`))
		case strings.HasSuffix(r.URL.Path, "/users/me/messages/m1"):
			_, _ = w.Write([]byte(`{
				"id":"m1",
				"threadId":"t1",
				"labelIds":["INBOX"],
				"snippet":"hello",
				"payload":{"mimeType":"text/plain","headers":[{"name":"Subject","value":"Hi"}],"body":{"data":"` + plain + `"}}
			}`))
		default:
			http.Error(w, "unexpected "+r.URL.String(), 404)
		}
	}))
	defer srv.Close()
	orig := gmail.BaseURL
	gmail.BaseURL = srv.URL
	t.Cleanup(func() { gmail.BaseURL = orig })

	configPath, tokenStorePath := withConfigPath(t)
	seedSendStore(t, tokenStorePath, "user@example.com", "gid-001")
	writeConfigPointingAt(t, configPath, "http://unused", "user@example.com")

	stdout, _, err := executeCmd(t, "--config", configPath, "--json", "messages", "list", "--query", "subject:Hi", "--full")
	if err != nil {
		t.Fatalf("messages list --full: %v", err)
	}
	if requests["/users/me/messages/m1"] != 1 {
		t.Fatalf("full message fetch count = %d want 1", requests["/users/me/messages/m1"])
	}
	if !strings.Contains(stdout, "hello body") {
		t.Fatalf("full output missing decoded body: %s", stdout)
	}
}

func TestMessagesListRequiresQuery(t *testing.T) {
	configPath, _ := withConfigPath(t)
	_, _, err := executeCmd(t, "--config", configPath, "messages", "list")
	if err == nil {
		t.Fatalf("expected missing query error")
	}
	if !strings.Contains(err.Error(), "--query is required") {
		t.Fatalf("error %q missing query hint", err.Error())
	}
}
